const REGIONS = [
  { id: 'argentina', label: 'Argentina',       projects: 44, x: 333.0, y: 346.0, r: 10 },
  { id: 'usa',       label: 'United States',   projects: 57, x: 259.2, y: 139.9, r: 12 },
  { id: 'spain',     label: 'España',          projects: 10, x: 473.3, y: 137.1, r:  7 },
  { id: 'mexico',    label: 'México',          projects:  8, x: 238.2, y: 185.2, r:  7 },
  { id: 'bolivia',   label: 'Bolivia',         projects:  6, x: 324.1, y: 297.9, r:  6 },
  { id: 'latam',     label: 'LATAM Regional',  projects: 16, x: 346.4, y: 264.1, r:  9 },
  { id: 'remote',    label: 'Global / Remote', projects: 78, x: 480.0, y:  95.9, r: 14 },
]

type Region = typeof REGIONS[number]

export default function WorldMap({ lang = 'es' }: { lang?: string }) {
  const [hovered, setHovered] = useState<Region | null>(null)
  const [pos, setPos] = useState({ x: 0, y: 0 })

  const onMove = (e: React.MouseEvent<SVGGElement>, r: Region) => {
    const svg = e.currentTarget.closest('svg') as SVGSVGElement
    const rect = svg.getBoundingClientRect()
    setPos({
      x: ((e.clientX - rect.left)  / rect.width)  * 960,
      y: ((e.clientY - rect.top)   / rect.height) * 500,
    })
    setHovered(r)
  }

  const totalProjects = REGIONS.reduce((a, r) => a + r.projects, 0)
  const mapLabel    = lang === 'es' ? 'Alcance geográfico' : 'Geographic reach'
  const projectsLbl = lang === 'es' ? 'proyectos' : 'projects'
  const marketsLbl  = lang === 'es' ? 'mercados'  : 'markets'

  return (
    <div className="w-full">
      {/* Header */}
      <div className="flex justify-between items-center mb-4">
        <span className="font-mono-bondy text-[10px] tracking-widest uppercase text-b-orange">
          {mapLabel}
        </span>
        <span className="font-mono-bondy text-[10px] tracking-widest text-white/20">
          {totalProjects}+ {projectsLbl} · {REGIONS.length} {marketsLbl}
        </span>
      </div>

      {/* Map */}
      <div className="relative w-full" style={{ paddingBottom: '52%' }}>
        <svg
          viewBox="0 0 960 500"
          className="absolute inset-0 w-full h-full"
          preserveAspectRatio="xMidYMid meet"
          style={{ overflow: 'visible' }}
        >
          {/* Countries — subtle land mass on dark bg */}
          {COUNTRIES.map(c => (
            <path
              key={c.id}
              d={c.d}
              fill="#1A1A1A"
              stroke="#2A2A2A"
              strokeWidth="0.5"
            />
          ))}

          {/* Sphere border */}
          <path d={SPHERE} fill="none" stroke="rgba(255,255,255,0.04)" strokeWidth="0.8" />

          {/* Region dots */}
          {REGIONS.map(r => {
            const h = hovered?.id === r.id
            return (
              <g
                key={r.id}
                onMouseMove={e => onMove(e, r)}
                onMouseLeave={() => setHovered(null)}
                style={{ cursor: 'pointer' }}
              >
                {/* Pulse ring */}
                {!h && (
                  <circle
                    cx={r.x} cy={r.y} r="4"
                    fill="none" stroke="#C06A2D" strokeWidth="1.2"
                    style={{
                      animation: 'mapPulse 2.6s ease-out infinite',
                      transformBox: 'fill-box',
                      transformOrigin: 'center',
                    }}
                  />
                )}
                {/* Hover glow */}
                {h && <circle cx={r.x} cy={r.y} r={r.r + 12} fill="rgba(192,106,45,0.07)" />}
                {/* Outer ring */}
                <circle
                  cx={r.x} cy={r.y}
                  r={h ? r.r + 2 : r.r}
                  fill={h ? 'rgba(192,106,45,0.2)' : 'rgba(192,106,45,0.10)'}
                  stroke={h ? '#C06A2D' : 'rgba(192,106,45,0.45)'}
                  strokeWidth={h ? 1.5 : 1}
                  style={{ transition: 'all .18s ease' }}
                />
                {/* Core */}
                <circle
                  cx={r.x} cy={r.y}
                  r={h ? 5 : 3.5}
                  fill={h ? '#F0A060' : '#C06A2D'}
                  style={{ transition: 'all .18s ease' }}
                />
              </g>
            )
          })}

          {/* Tooltip */}
          {hovered && (() => {
            const flipX = pos.x > 720
            const flipY = pos.y > 400
            const tx = pos.x + (flipX ? -172 : 20)
            const ty = pos.y + (flipY ? -84  : 16)
            return (
              <g transform={`translate(${tx},${ty})`} style={{ pointerEvents: 'none', animation: 'tipIn .15s ease forwards' }}>
                <rect width="156" height="72" rx="2" fill="#141414" stroke="rgba(192,106,45,0.55)" strokeWidth=".8" />
                <rect width="156" height="3" rx="1" fill="#C06A2D" />
                <text x="12" y="22" style={{ fontFamily: 'var(--font-dm-sans)', fontSize: '13px', fontWeight: 500, fill: '#F4F2EE' }}>
                  {hovered.label}
                </text>
                <line x1="12" y1="29" x2="144" y2="29" stroke="rgba(255,255,255,0.07)" strokeWidth=".7" />
                <text x="12" y="46" style={{ fontFamily: 'var(--font-dm-mono)', fontSize: '8px', letterSpacing: '.14em', fill: 'rgba(255,255,255,0.28)', textTransform: 'uppercase' }}>
                  {projectsLbl.toUpperCase()}
                </text>
                <text x="12" y="65" style={{ fontFamily: 'var(--font-playfair)', fontSize: '22px', fontWeight: 700, fill: '#C06A2D' }}>
                  {hovered.projects}+
                </text>
              </g>
            )
          })()}
        </svg>
      </div>

      <style>{`
        @keyframes mapPulse {
          0%   { r: 4px; opacity: .6; }
          80%  { r: 20px; opacity: 0; }
          100% { r: 4px; opacity: 0; }
        }
        @keyframes tipIn {
          from { opacity: 0; }
          to   { opacity: 1; }
        }
      `}</style>
    </div>
  )
}
